// ===================================================
// WF-12 Step 1: today-7 날짜 계산 (KST 기준)
// 수업 완료 후 7일 뒤에 후기 요청 이메일 발송
// ===================================================

const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);

const pad = (n) => String(n).padStart(2, '0');

const d7Ago = new Date(kst.getTime());
d7Ago.setDate(d7Ago.getDate() - 7);

const targetDate = d7Ago.getFullYear() + '-' + pad(d7Ago.getMonth() + 1) + '-' + pad(d7Ago.getDate());
const todayStr = kst.getFullYear() + '-' + pad(kst.getMonth() + 1) + '-' + pad(kst.getDate());

return [{
  json: {
    targetDate,
    todayStr
  }
}];

// ===================================================
// WF-12 Step 2: 대상 목록 파싱 + 유효성 필터링
// student_email이 존재하고, REVIEW_SENT가 없는 건만 대상
// ===================================================

const response = $input.first().json;
const list = response.list || [];

if (list.length === 0) {
  return [{
    json: {
      _hasTargets: false,
      _totalCount: 0
    }
  }];
}

const items = [];

for (const row of list) {
  const studentEmail = String(row.student_email || '').trim();
  const emailSent = String(row.student_email_sent || '');
  const recordId = row.Id || row.id || '';

  // 수강생 이메일이 없으면 스킵
  if (!studentEmail || studentEmail.indexOf('@') === -1) continue;

  // 이중 안전장치: REVIEW_SENT 포함 여부 재확인
  if (emailSent.indexOf('REVIEW_SENT') !== -1) continue;

  items.push({
    ...row,
    _recordId: recordId,
    _studentEmail: studentEmail,
    _partnerCode: String(row.partner_code || ''),
    _currentEmailSent: emailSent
  });
}

if (items.length === 0) {
  return [{
    json: {
      _hasTargets: false,
      _totalCount: 0
    }
  }];
}

return items.map(item => ({
  json: {
    ...item,
    _hasTargets: true,
    _totalCount: items.length
  }
}));

// WF-12 대상 없음 텔레그램 메시지
const dates = $('Calculate Target Date').first().json;

return [{
  json: {
    _telegramMessage: '\u2705 *후기 요청 발송 (' + dates.todayStr + ')*\n\n오늘 발송 대상이 없습니다. (대상일: ' + dates.targetDate + ')'
  }
}];

// ===================================================
// WF-12 Step 3: 후기 요청 이메일 HTML 빌드
// 수강생: email-templates.md 이메일 4 (후기 요청 + 적립금 인센티브)
// 파트너: 후기 접수 안내
// XSS 방지: 모든 동적 값 escapeHtml 처리
// ===================================================

const settlement = $('Filter Review Targets').first().json;
const classResponse = $('NocoDB Get Class').first().json;
const partnerResponse = $('NocoDB Get Partner').first().json;

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// 클래스 정보
const classList = classResponse.list || [];
const classData = classList.length > 0 ? classList[0] : {};
const className = escapeHtml(classData.class_name || settlement.class_name || '');

// 파트너 정보
const partnerList = partnerResponse.list || [];
const partner = partnerList.length > 0 ? partnerList[0] : {};
const partnerName = escapeHtml(partner.partner_name || '');
const partnerEmail = String(partner.email || '').trim();

// 수강생 정보
const studentName = escapeHtml(settlement.student_name || '고객');
const studentEmail = settlement._studentEmail;
const classDate = escapeHtml(String(settlement.class_date || '').substring(0, 10));
const recordId = settlement._recordId;
const currentEmailSent = settlement._currentEmailSent;

const reviewUrl = 'https://foreverlove.co.kr/shop/page.html?id=2607&class_id=' + encodeURIComponent(String(settlement.class_id || ''));
const myPageUrl = 'https://foreverlove.co.kr/shop/page.html?id=2609';

// 공통 조각
const header = '<tr><td style="padding: 24px 32px; text-align: center; border-bottom: 2px solid #b89b5e;">'
  + '<span style="font-size: 22px; font-weight: 700; color: #b89b5e; letter-spacing: 2px;">PRESSCO21</span><br />'
  + '<span style="font-size: 11px; color: #999999; letter-spacing: 1px;">Forever and ever and Blooming</span>'
  + '</td></tr>';

const signature = '<tr><td style="padding: 0 32px 32px;"><p style="margin: 0; font-size: 14px; color: #b89b5e; font-weight: 600;">PRESSCO21 드림</p></td></tr>';

const footer = '<tr><td style="padding: 24px 32px; text-align: center; background-color: #faf8f3; border-top: 1px solid #e8e4db;">'
  + '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">PRESSCO21 | foreverlove.co.kr</p>'
  + '<p style="margin: 0; font-size: 11px; color: #bbbbbb;">이 메일은 PRESSCO21 클래스 예약 관련 안내 메일입니다.</p>'
  + '</td></tr>';

const wrapStart = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /></head>'
  + '<body style="margin: 0; padding: 0; background-color: #f8f6f0; font-family: Pretendard, Apple SD Gothic Neo, Malgun Gothic, sans-serif;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8f6f0;"><tr><td align="center" style="padding: 24px 16px;">'
  + '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">';

const wrapEnd = '</table></td></tr></table></body></html>';

// === 수강생 후기 요청 이메일 ===
const studentSubject = '[PRESSCO21] 수업은 즐거우셨나요? 후기를 남겨주세요';

const studentHtml = wrapStart + header
  + '<tr><td style="padding: 40px 32px 32px;">'
  + '<p style="margin: 0 0 20px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + studentName + '</strong>님, 안녕하세요!</p>'
  + '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">지난 <strong>' + classDate + '</strong>에 참여해주신</p>'
  + '<p style="margin: 0 0 24px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + className + '</strong>, 즐거우셨나요?</p>'
  + '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;">' + partnerName + ' 선생님과 함께한 시간이 좋은 추억이 되셨길 바라요.<br />소중한 경험을 다른 분들에게도 나눠주시면 큰 도움이 됩니다.</p>'
  // 별점
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 24px;"><tr><td align="center" style="padding: 20px 0;">'
  + '<span style="font-size: 28px; letter-spacing: 4px; color: #b89b5e;">&#9733; &#9733; &#9733; &#9733; &#9733;</span><br />'
  + '<span style="font-size: 13px; color: #999999; display: inline-block; margin-top: 8px;">수업은 어떠셨나요?</span>'
  + '</td></tr></table>'
  // 인센티브
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #fef9f0; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 28px;">'
  + '<tr><td style="padding: 20px 24px; text-align: center;">'
  + '<p style="margin: 0 0 8px; font-size: 14px; color: #b89b5e; font-weight: 700;">사진 후기를 남겨주시면</p>'
  + '<p style="margin: 0 0 4px; font-size: 22px; color: #b89b5e; font-weight: 700;">1,000원 적립금</p>'
  + '<p style="margin: 0; font-size: 13px; color: #999999;">을 드려요!</p>'
  + '</td></tr></table>'
  // CTA
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 18px;"><tr><td align="center">'
  + '<a href="' + reviewUrl + '" style="display: inline-block; background-color: #b89b5e; color: #ffffff; font-size: 15px; font-weight: 600; text-decoration: none; padding: 14px 40px; border-radius: 6px; letter-spacing: 0.5px;">후기 작성하고 다시 보기</a>'
  + '</td></tr></table>'
  + '<p style="margin: 0 0 24px; font-size: 13px; color: #777777; line-height: 1.8; text-align: center;">후기를 남긴 뒤에는 <a href="' + myPageUrl + '" style="color: #b89b5e; font-weight: 700; text-decoration: none;">내 수강 내역</a>에서 같은 강사의 다음 수업과 재료 재구매를 바로 이어볼 수 있어요.</p>'
  // 후기 안내
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 24px;"><tr><td style="padding: 16px 20px; background-color: #f5f5f5; border-radius: 8px;">'
  + '<p style="margin: 0 0 8px; font-size: 14px; font-weight: 700; color: #333333;">후기 작성 안내</p>'
  + '<ul style="margin: 0; padding-left: 20px; color: #666; font-size: 13px; line-height: 1.8;">'
  + '<li>솔직한 수업 후기를 남겨 주세요.</li>'
  + '<li>사진 첨부 시 적립금이 추가 지급됩니다.</li>'
  + '<li>작성 후 1~2일 내 적립금이 자동 지급됩니다.</li>'
  + '</ul></td></tr></table>'
  // 마무리
  + '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">작성해주신 후기는 ' + partnerName + ' 선생님에게 큰 힘이 됩니다.</p>'
  + '<p style="margin: 0; font-size: 15px; color: #333333; line-height: 1.7;">감사합니다!</p>'
  + '</td></tr>' + signature + footer + wrapEnd;

// === 파트너 후기 알림 이메일 ===
const partnerSubject = '[PRESSCO21] 수강생 후기 확인 안내 - ' + (classData.class_name || '');

const partnerHtml = wrapStart + header
  + '<tr><td style="padding: 40px 32px 32px;">'
  + '<p style="margin: 0 0 20px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + partnerName + '</strong>님, 안녕하세요!</p>'
  + '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + className + '</strong> 수업에 대한 후기 작성 요청이 수강생에게 발송되었습니다.</p>'
  + '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;">파트너 대시보드에서 후기를 확인하고 답변해 주시면,<br />수강생 만족도와 재수강률이 높아집니다.</p>'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 24px;">'
  + '<tr><td style="padding: 20px 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0">'
  + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999; width: 80px;">클래스</td><td style="padding: 6px 0; font-size: 14px; color: #333333; font-weight: 600;">' + className + '</td></tr>'
  + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999;">수강일</td><td style="padding: 6px 0; font-size: 14px; color: #333333;">' + classDate + '</td></tr>'
  + '</table></td></tr></table>'
  // CTA
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 32px;"><tr><td align="center">'
  + '<a href="https://foreverlove.co.kr/partner/dashboard" style="display: inline-block; background-color: #b89b5e; color: #ffffff; font-size: 15px; font-weight: 600; text-decoration: none; padding: 14px 40px; border-radius: 6px; letter-spacing: 0.5px;">대시보드에서 확인하기</a>'
  + '</td></tr></table>'
  + '<p style="margin: 0; font-size: 13px; color: #888888;">* 후기에 대한 감사 답변은 클래스 평점 향상에 도움이 됩니다.</p>'
  + '</td></tr>' + signature + footer + wrapEnd;

return [{
  json: {
    ...settlement,
    _studentEmailData: { to: studentEmail, subject: studentSubject, html: studentHtml },
    _partnerEmailData: { to: partnerEmail, subject: partnerSubject, html: partnerHtml },
    _hasPartnerEmail: !!(partnerEmail && partnerEmail.indexOf('@') !== -1),
    _recordId: recordId,
    _currentEmailSent: currentEmailSent,
    _newEmailSent: currentEmailSent + (currentEmailSent ? ',' : '') + 'REVIEW_SENT'
  }
}];

// WF-12 결과 집계 + 텔레그램
const allItems = $('Filter Review Targets').all();
const totalCount = allItems.filter(i => i.json._hasTargets).length;
const dates = $('Calculate Target Date').first().json;

const message = '\u2709\uFE0F *후기 요청 발송 완료 (' + dates.todayStr + ')*\n\n'
  + '대상일: ' + dates.targetDate + ' 수강건\n'
  + '발송: ' + totalCount + '건\n'
  + '적립금 인센티브: 1,000원 (사진 후기)';

return [{
  json: {
    _telegramMessage: message
  }
}];
